const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { message: 'No escalations today.' } }];
}

const today = new Date().toLocaleDateString('en-US', {
  month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC'
});

const lines = items.map(function(item) {
  var d = item.json;
  var oldest = new Date(d.oldest_ticket_date).toLocaleDateString('en-US', {
    month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC'
  });
  var count = Number(d.open_ticket_count);
  var ticketWord = count === 1 ? 'ticket' : 'tickets';
  var agents = d.assignees || 'Unassigned';
  return '- *' + d.account_name + '* -- ' + count + ' ' + ticketWord + ' | Oldest: ' + oldest + ' | Agents: ' + agents;
});

var totalTickets = items.reduce(function(sum, i) {
  return sum + Number(i.json.open_ticket_count);
}, 0);
var totalAccounts = items.length;

var header = ':rotating_light: *Onboarding Escalation Report* -- ' + today;
var subheader = 'Open tickets older than 5 days in the Onboarding queue:';
var footer = '*Total: ' + totalAccounts + ' account' + (totalAccounts === 1 ? '' : 's') + ' | ' + totalTickets + ' ticket' + (totalTickets === 1 ? '' : 's') + ' need attention.*';

var message = [header, subheader, ''].concat(lines).concat(['', footer]).join('\n');

return [{ json: { message: message } }];
